      secret:      'YOUR_SECRET_TOKEN',
      environment: 'production',
      alertLevel:  'high'
    },
    {
      id:          'vps-01',
      name:        'VPS 1',
      url:         'http://YOUR_SERVER_IP:3000',
      secret:      'YOUR_SECRET_TOKEN',
      environment: 'production',
      alertLevel:  'high'
    },

    // ← aggiungi altri server qui con lo stesso formato
  ]
};

