// 1. Recupero dati: usiamo la sintassi corretta per accoppiare gli indici
const config = $("VPS List").item.json; 
const stats = $input.item.json;
const thresh = config.thresholds;

// 2. Gestione errori di connessione
if (stats.error) {
  return {
    json: {
      vps_id: config.id,
      vps_name: config.name,
      environment: config.environment,
      alert_level: config.alertLevel,
      admin_telegram_id: config.admin_telegram_id,
      stats_error: stats.error,
      metric_alerts: [`❌ Errore agente: ${stats.error}`],
      has_metric_alerts: true,
      ai_payload: { host: config.name, unrecognized_procs: "[]", failed_auth: "" }
    }
  };
}

const alerts = [];

// 3. Valutazione Metriche (RAM, CPU, Disco)
const mem = stats.memory || {};
if (mem.percent_used >= thresh.memory_percent) {
  alerts.push(`🔴 RAM al ${mem.percent_used}% (soglia ${thresh.memory_percent}%)`);
}

const cpu = stats.cpu || {};
if (cpu.percent_used >= thresh.cpu_percent) {
  alerts.push(`🔴 CPU al ${cpu.percent_used}% (soglia ${thresh.cpu_percent}%)`);
}

const disks = stats.disks || [];
for (const disk of disks) {
  if (disk.percent >= thresh.disk_percent) {
    alerts.push(`🔴 DISCO ${disk.mount} al ${disk.percent}%`);
  }
}

// 4. Sicurezza (Login falliti)
const failedCount = stats.security?.failed_auth_count || 0;
if (failedCount >= thresh.failed_logins) {
  alerts.push(`🔴 SICUREZZA: ${failedCount} tentativi falliti!`);
}

// 5. OUTPUT CORRETTO (Impacchettato per n8n)
return {
  json: {
    vps_id:             config.id,
    vps_name:           config.name,
    environment:        config.environment,
    alert_level:        config.alertLevel,
    admin_telegram_id:  config.admin_telegram_id,
    stats:              stats,
    metric_alerts:      alerts,
    has_metric_alerts:  alerts.length > 0,
    ai_payload: {
      host:               stats.host || config.name,
      environment:        config.environment,
      unrecognized_procs: JSON.stringify(stats.processes || []),
      open_ports:         JSON.stringify(stats.security?.listening_ports || []),
      disk_percent_max:   Math.max(...(stats.disks || []).map(d => d.percent), 0),
      last_logins:        (stats.security?.last_logins || []).join('\n'),
      failed_auth:        (stats.security?.failed_auth || []).join('\n'),
      logged_users:       (stats.security?.logged_users || []).join('\n')
    }
  }
};

