const item      = $input.item.json;
const ai        = item.output || {};
const hasMal    = (ai.malicious || '').trim().length > 0;
const hasSusp   = (ai.suspicious || '').trim().length > 0;
const hasMetric = item.has_metric_alerts;

let severity = 'clean';
if (hasMal)              severity = 'compromised';
else if (hasSusp || hasMetric) severity = 'warning';

const stats = item.stats || {};
const mem   = stats.memory || {};
const cpu   = stats.cpu || {};
const disks = stats.disks || [];
const maxDisk = disks.length > 0 ? Math.max(...disks.map(d => d.percent)) : 0;

return {
  json: {
    ...item,
    ai,
    severity,
    has_malicious:   hasMal,
    has_suspicious:  hasSusp,
    has_metric_alerts: hasMetric,
    needs_alert:     hasMal || hasSusp || hasMetric,
    // Sommario leggibile per Telegram
    summary: {
      ram_percent:   mem.percent_used || 0,
      ram_used_mb:   mem.used_mb || 0,
      ram_total_mb:  mem.total_mb || 0,
      cpu_percent:   cpu.percent_used || 0,
      cpu_load1:     cpu.load1 || 0,
      cpu_cores:     cpu.cores || 1,
      max_disk:      maxDisk,
      uptime_h:      stats.uptime_hours || 0,
      connections:   stats.network?.established_connections || 0,
      failed_auth:   stats.security?.failed_auth_count || 0,
      logged_users:  (stats.security?.logged_users || []).length
    }
  }
};

